import "./signUp.css"

export const SignUp = () => {
    const handleSubmit = (e) => {
        e.preventDefault()
    }
  return (
    <div className="signUp">
        <form onSubmit={handleSubmit}>
            <label>Email</label>
            <input type="email" />
            <label>Username</label>
            <input type="text" />
            <label>Password</label>
            <input type="text" />

            <button>Sign Up</button>
        </form>
    </div>
  )
}
